Use case 3 — Reusable client with caching

In a real application you rarely want to call the API on every request. This client caches the result for a configurable duration:

package ipdetect
import (
"encoding/json"
"fmt"
"io"
"net/http"
"sync"
"time"
)
type Client struct {
httpClient *http.Client
cacheTTL time.Duration
mu sync.Mutex
cached *IPInfo
cachedAt time.Time
}
type IPInfo struct {
IP string `json:"ip"`
Country string `json:"country"`
City string `json:"city"`
ISP string `json:"isp"`
ASN string `json:"asn"`
}
func NewClient(cacheTTL time.Duration) *Client {
return &Client{
httpClient: &http.Client{Timeout: 10 * time.Second},
cacheTTL: cacheTTL,
}
}
func (c *Client) Get() (*IPInfo, error) {
c.mu.Lock()
defer c.mu.Unlock()
if c.cached != nil && time.Since(c.cachedAt) < c.cacheTTL {
return c.cached, nil
}
resp, err := c.httpClient.Get("https://ippubblico.org/?api=1")
if err != nil {
return nil, fmt.Errorf("request failed: %w", err)
}
defer resp.Body.Close()
body, err := io.ReadAll(resp.Body)
if err != nil {
return nil, fmt.Errorf("read body: %w", err)
}
var raw struct {
Status string `json:"status"`
IP string `json:"ip"`
ISP string `json:"isp"`
ASN string `json:"asn"`
Geo struct {
Country string `json:"country"`
City string `json:"city"`
} `json:"geo"`
}
if err := json.Unmarshal(body, &raw); err != nil {
return nil, fmt.Errorf("parse JSON: %w", err)
}
info := &IPInfo{
IP: raw.IP,
ISP: raw.ISP,
ASN: raw.ASN,
Country: raw.Geo.Country,
City: raw.Geo.City,
}
c.cached = info
c.cachedAt = time.Now()
return info, nil
}

