r := gin.Default()
r.Use(middleware.GeoMiddleware())
r.GET("/content", func(c *gin.Context) {
country, _ := c.Get("country_code")
c.JSON(200, gin.H{
"country": country,
"content": "Hello from " + fmt.Sprint(country),
})
})

